const grpc = require('grpc');
const http = require('http');

const client = new grpc.Client('your-service', 'localhost:50051', grpc.credentials.createInsecure());

function handleRequest(req, res) {
  const headers = req.headers;
  const metadata = new grpc.Metadata();

  // Add custom headers to the gRPC metadata
  for (const header of Object.keys(headers)) {
    if (header !== 'user-agent' && header !== 'x-forwarded-for') {
      metadata.add(header, headers[header]);
    }
  }

  // Forward the request to the gRPC service
  client.makeUnaryRequest('your-method', {}, metadata, (err, response) => {
    if (err) {
      res.status(500).send(err);
    } else {
      res.json(response);
    }
  });
}

const server = http.createServer(handleRequest);
server.listen(8080, () => {
  console.log('Listening on port 8080');
});